      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json() as { projects?: PiWebProjectRecord[]; error?: string };
      if (data.error) throw new Error(data.error);
      setProjects(data.projects ?? []);
      setError(null);
      if (!showLoading) {
        setProjectsRefreshDone(true);
        if (sessionRefreshTimerRef.current) clearTimeout(sessionRefreshTimerRef.current);
        sessionRefreshTimerRef.current = setTimeout(() => setProjectsRefreshDone(false), 2000);
      }
    } catch (e) {
      setError(String(e));
    } finally {
      if (showLoading) setLoading(false);
    }
  }, []);

  const loadSessions = useCallback(async (showLoading = false) => {
    const token = ++loadSessionsTokenRef.current;
    loadSessionsAbortRef.current?.abort();
    const controller = new AbortController();
    loadSessionsAbortRef.current = controller;
    const selected = findProjectSpace(projectsRef.current, selectedProjectId, selectedSpaceId);
    if (!selected) {
      if (token === loadSessionsTokenRef.current) {
        // Only clear when there is no selection intent. If project/space ids are
        // already set (URL restore) but the projects registry has not loaded yet,
        // keep the current list and wait for a later retry.
        if (!selectedProjectId || !selectedSpaceId) {
          setAllSessions([]);
        }
        setSessionsSwitching(false);
        if (showLoading) setLoading(false);
      }
      return;
    }
    try {
      if (showLoading) {
        if (token === loadSessionsTokenRef.current) {
          setSessionsSwitching(true);
          setLoading(true);
          setAllSessions([]);
          setSelectedForArchive(new Set());
        }
      }
      const res = await fetch(`/api/projects/${encodeURIComponent(selected.project.id)}/spaces/${encodeURIComponent(selected.space.id)}/sessions`, {
        signal: controller.signal,
      });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json() as { sessions?: SessionInfo[]; error?: string };
      if (data.error) throw new Error(data.error);
      if (token !== loadSessionsTokenRef.current) return;
      setAllSessions(data.sessions ?? []);
      setError(null);
      if (!showLoading) {
        setSessionRefreshDone(true);
        if (sessionRefreshTimerRef.current) clearTimeout(sessionRefreshTimerRef.current);
        sessionRefreshTimerRef.current = setTimeout(() => setSessionRefreshDone(false), 2000);
      }
    } catch (e) {
      if (controller.signal.aborted || (e instanceof DOMException && e.name === "AbortError")) return;
      if (token !== loadSessionsTokenRef.current) return;
      setError(String(e));
    } finally {
      if (token === loadSessionsTokenRef.current) {
        if (showLoading) setLoading(false);
        setSessionsSwitching(false);
      }
    }
  }, [selectedProjectId, selectedSpaceId]);

  const handleArchiveSession = useCallback(async (sessionId: string) => {
    try {
