        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ sessionIds: [sessionId] }),
      });
      if (res.ok) {
        setSelectedForArchive((prev) => {
          const next = new Set(prev);
          next.delete(sessionId);
          return next;
        });
        void loadSessions(false);
      }
    } catch {
      // ignore
    }
  }, [loadSessions]);

